// Rust-faithful Dafny port of src/parsers/toml.rs.
// External Bun AST/lexer/runtime primitives are represented by narrow local
// Dafny models so the parser control flow can stay close to the Rust source.

module Toml {
  datatype T =
    t_comma | t_string_literal | t_identifier | t_false | t_true |
    t_numeric_literal | t_dot | t_end_of_file | t_open_bracket |
    t_close_bracket | t_open_bracket_double | t_close_bracket_double |
    t_empty_array | t_minus | t_plus | t_open_brace | t_close_brace |
    t_equal

  datatype SetError = Clobber | Other

  class Loc {
    var start: int
    constructor(start_: int) { start := start_; }
  }

  class Source {
    var contents: seq<int>
    constructor(contents_: seq<int>) { contents := contents_; }
  }

  datatype ExprData =
    DObject(obj: Object) | DArray(arr: Array) | DString(bytes: seq<int>) |
    DBoolean(boolValue: bool) | DNumber(numValue: real) | DNull

  class Expr {
    var loc: Loc
    var data: ExprData
    constructor(data_: ExprData, loc_: Loc) {
      loc := loc_;
      data := data_;
    }
  }

  class Property {
    var key: Expr?
    var value: Expr?
    constructor(key_: Expr?, value_: Expr?) {
      key := key_;
      value := value_;
    }
  }

  class Array {
    var items: seq<Expr>
    constructor() { items := []; }
    method {:verify false} Push(value: Expr)
      modifies this
    {
      items := items + [value];
    }
  }

  class Rope {
    var head: Expr
    var next: Rope?
    constructor(head_: Expr, next_: Rope?) {
      head := head_;
      next := next_;
    }

    method {:verify false} Append(seg: Expr) returns (out: Rope)
      modifies this
    {
      var node := new Rope(seg, null);
      next := node;
      out := node;
    }
  }

  datatype MaybeSeq = NoSeq | SomeSeq(bytes: seq<int>)

  function EString(e: Expr): MaybeSeq
    reads e
  {
    match e.data
    case DString(bytes) => SomeSeq(bytes)
    case _ => NoSeq
  }

  function IsSomeString(m: MaybeSeq): bool {
    match m
    case SomeSeq(_) => true
    case NoSeq => false
  }

  function FromSomeString(m: MaybeSeq): seq<int>
    requires IsSomeString(m)
  {
    match m
    case SomeSeq(bytes) => bytes
    case NoSeq => []
  }

  class Object {
    var properties: seq<Property>

    constructor() { properties := []; }

    method {:verify false} Get(key: seq<int>) returns (existing: Expr?)
    {
      existing := null;
      var i := 0;
      while i < |properties|
        invariant 0 <= i <= |properties|
      {
        var p := properties[i];
        if p.key != null && p.value != null {
          match EString(p.key)
          case SomeSeq(bytes) =>
            if bytes == key {
              existing := p.value;
              return;
            }
          case NoSeq =>
        }
        i := i + 1;
      }
    }

    method {:verify false} SetRope(rope: Rope, value: Expr) returns (ok: bool, err: SetError)
      modifies this
      decreases *
    {
      var maybeHeadKey := EString(rope.head);
      if !IsSomeString(maybeHeadKey) {
        ok := false; err := Clobber; return;
      }
      var headKey := FromSomeString(maybeHeadKey);
      var existing := Get(headKey);
      if existing != null {
        match existing.data
        case DArray(arr) =>
          if rope.next == null {
            arr.Push(value);
            ok := true; err := Other; return;
          }
          if |arr.items| > 0 {
            var last := arr.items[|arr.items| - 1];
            match last.data
            case DObject(obj) =>
              ok, err := obj.SetRope(rope.next, value);
              return;
            case _ =>
              ok := false; err := Clobber; return;
          }
          arr.Push(value);
          ok := true; err := Other; return;
        case DObject(obj2) =>
          if rope.next != null {
            ok, err := obj2.SetRope(rope.next, value);
            return;
          }
          ok := false; err := Clobber; return;
        case _ =>
          ok := false; err := Clobber; return;
      }

      var value_ := value;
      if rope.next != null {
        var obj := new Object();
        var exprObj := new Expr(DObject(obj), rope.head.loc);
        ok, err := obj.SetRope(rope.next, value);
        if !ok { return; }
        value_ := exprObj;
      }

      var prop := new Property(rope.head, value_);
      properties := properties + [prop];
      ok := true; err := Other;
    }

    method {:verify false} GetOrPutObject(rope: Rope) returns (ok: bool, out: Expr?, err: SetError)
      modifies this
      decreases *
    {
      var maybeHeadKey := EString(rope.head);
      if !IsSomeString(maybeHeadKey) {
        ok := false; out := null; err := Clobber; return;
      }
      var existing := Get(FromSomeString(maybeHeadKey));
      if existing != null {
        match existing.data
        case DObject(obj2) =>
          if rope.next != null {
            ok, out, err := obj2.GetOrPutObject(rope.next);
            return;
          }
          ok := true; out := existing; err := Other; return;
        case _ =>
          ok := false; out := null; err := Clobber; return;
      }
      var obj := new Object();
      var exprObj := new Expr(DObject(obj), rope.head.loc);
      var prop := new Property(rope.head, exprObj);
      properties := properties + [prop];
      if rope.next != null {
        ok, out, err := obj.GetOrPutObject(rope.next);
      } else {
        ok := true; out := exprObj; err := Other;
      }
    }

    method {:verify false} GetOrPutArray(rope: Rope) returns (ok: bool, out: Expr?, err: SetError)
      modifies this
      decreases *
    {
      var maybeHeadKey := EString(rope.head);
      if !IsSomeString(maybeHeadKey) {
        ok := false; out := null; err := Clobber; return;
      }
      var headKey := FromSomeString(maybeHeadKey);
      var existing := Get(headKey);
      if existing != null {
        match existing.data
        case DArray(arr) =>
          if rope.next == null {
            ok := true; out := existing; err := Other; return;
          }
          if |arr.items| > 0 {
            var last := arr.items[|arr.items| - 1];
            match last.data
            case DObject(obj) =>
              ok, out, err := obj.GetOrPutArray(rope.next);
              return;
            case _ =>
              ok := false; out := null; err := Clobber; return;
          }
          ok := false; out := null; err := Clobber; return;
        case DObject(obj2) =>
          if rope.next == null {
            ok := false; out := null; err := Clobber; return;
          }
          ok, out, err := obj2.GetOrPutArray(rope.next);
          return;
        case _ =>
          ok := false; out := null; err := Clobber; return;
      }

      if rope.next != null {
        var obj := new Object();
        var exprObj := new Expr(DObject(obj), rope.head.loc);
        ok, out, err := obj.GetOrPutArray(rope.next);
        if !ok { return; }
        var prop := new Property(rope.head, exprObj);
        properties := properties + [prop];
        return;
      }

      var arr := new Array();
      var outExpr := new Expr(DArray(arr), rope.head.loc);
      var prop := new Property(rope.head, outExpr);
      properties := properties + [prop];
      ok := true; out := outExpr; err := Other;
    }
  }

  datatype LexItem = LexItem(tok: T, text: seq<int>, num: real, loc: int, newlineBefore: bool)

  class Lexer {
    var source: Source
    var stream: seq<LexItem>
    var index: int
    var token: T
    var identifier: seq<int>
    var number: real
    var has_newline_before: bool
    var allow_double_bracket: bool
    var start: int

    constructor(source_: Source, stream_: seq<LexItem>)
    {
      source := source_;
      stream := stream_;
      index := 0;
      identifier := [];
      number := 0.0;
      has_newline_before := false;
      allow_double_bracket := true;
      start := 0;
      if |stream_| == 0 {
        token := t_end_of_file;
      } else {
        token := stream_[0].tok;
        identifier := stream_[0].text;
        number := stream_[0].num;
        start := stream_[0].loc;
        has_newline_before := stream_[0].newlineBefore;
      }
    }

    method {:verify false} Loc() returns (loc: Loc) { loc := new Loc(start); }

    method {:verify false} Next() returns (ok: bool)
      modifies this
    {
      index := index + 1;
      if index < |stream| {
        token := stream[index].tok;
        identifier := stream[index].text;
        number := stream[index].num;
        start := stream[index].loc;
        has_newline_before := stream[index].newlineBefore;
      } else {
        token := t_end_of_file;
        identifier := [];
        number := 0.0;
        has_newline_before := true;
      }
      ok := true;
    }

    method {:verify false} Expect(t: T) returns (ok: bool)
      modifies this
    {
      if token != t { ok := false; return; }
      ok := Next();
    }

    method {:verify false} ExpectAssignment() returns (ok: bool)
      modifies this
    {
      ok := Expect(t_equal);
    }

    method {:verify false} ToString(loc: Loc) returns (e: Expr)
    {
      e := new Expr(DString(identifier), loc);
    }

    method {:verify false} Raw() returns (bytes: seq<int>)
    {
      bytes := identifier;
    }

    method {:verify false} ExpectedString(unused: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} AddDefaultError(unused: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} AddError(unusedStart: int, unusedMessage: seq<int>) returns (ok: bool) { ok := false; }
    method {:verify false} Unexpected() returns (ok: bool) { ok := false; }
  }

  class StackCheck {
    constructor() {}
    method {:verify false} IsSafeToRecurse() returns (ok: bool) { ok := true; }
  }

  class HashMapPoolNode {
    var data: set<int>
    var next: HashMapPoolNode?
    constructor() { data := {}; next := null; }
  }

  class HashMapPool {
    var list: HashMapPoolNode?
    constructor() { list := null; }

    method {:verify false} Get() returns (node: HashMapPoolNode)
      modifies this
    {
      if list != null {
        node := list;
        list := node.next;
        node.data := {};
        node.next := null;
        return;
      }
      node := new HashMapPoolNode();
    }

    method {:verify false} Release(node: HashMapPoolNode)
      modifies this, node
    {
      node.next := list;
      list := node;
    }
  }

  class TOML {
    var lexer: Lexer
    var bump: object?
    var stack_check: StackCheck

    constructor(source_: Source, stream_: seq<LexItem>)
    {
      lexer := new Lexer(source_, stream_);
      bump := null;
      stack_check := new StackCheck();
    }

    method {:verify false} Source_() returns (source: Source)
    {
      source := lexer.source;
    }

    method {:verify false} E(data: ExprData, loc: Loc) returns (expr: Expr)
    {
      expr := new Expr(data, loc);
    }

    static method {:verify false} Parse(source_: Source, stream_: seq<LexItem>) returns (ok: bool, expr: Expr?)
      decreases *
    {
      if |source_.contents| == 0 {
        var emptyLoc := new Loc(0);
        var obj := new Object();
        expr := new Expr(DObject(obj), emptyLoc);
        ok := true;
        return;
      }

      var parser := new TOML(source_, stream_);
      ok, expr := parser.RunParser();
    }

    method {:verify false} ParseMaybeTrailingComma(closer: T) returns (ok: bool, keepGoing: bool)
      modifies lexer
    {
      ok := lexer.Expect(t_comma);
      if !ok { keepGoing := false; return; }

      if lexer.token == closer {
        keepGoing := false;
        return;
      }

      keepGoing := true;
    }

    method {:verify false} ParseKeySegment() returns (ok: bool, out: Expr?)
      modifies lexer
    {
      var loc := lexer.Loc();

      match lexer.token
      case t_string_literal =>
        var str := lexer.ToString(loc);
        ok := lexer.Next();
        out := str;
      case t_identifier =>
        var str := new Expr(DString(lexer.identifier), loc);
        ok := lexer.Next();
        out := str;
      case t_false =>
        ok := lexer.Next();
        out := new Expr(DString([102, 97, 108, 115, 101]), loc);
      case t_true =>
        ok := lexer.Next();
        out := new Expr(DString([116, 114, 117, 101]), loc);
      case t_numeric_literal =>
        var literal := lexer.Raw();
        ok := lexer.Next();
        out := new Expr(DString(literal), loc);
      case _ =>
        ok := true;
        out := null;
    }

    method {:verify false} ParseKey() returns (ok: bool, out: Rope?)
      modifies lexer
      decreases *
    {
      var segOk: bool;
      var first: Expr?;
      segOk, first := ParseKeySegment();
      if !segOk { ok := false; out := null; return; }
      if first == null {
        var _ := lexer.ExpectedString([107, 101, 121]);
        ok := false; out := null; return;
      }
      var rope := new Rope(first, null);
      var head := rope;
      var tail := rope;

      while lexer.token == t_dot
        decreases *
      {
        ok := lexer.Next();
        if !ok { out := null; return; }

        var seg: Expr?;
        segOk, seg := ParseKeySegment();
        if !segOk { ok := false; out := null; return; }
        if seg == null {
          break;
        }
        tail := tail.Append(seg);
      }

      ok := true;
      out := head;
    }

    method {:verify false} RunParser() returns (ok: bool, rootOut: Expr?)
      modifies this, lexer
      decreases *
    {
      var loc0 := lexer.Loc();
      var rootObj := new Object();
      var root := new Expr(DObject(rootObj), loc0);
      var head := rootObj;

      while true
        decreases *
      {
        var loc := lexer.Loc();
        match lexer.token
        case t_end_of_file =>
          ok := true; rootOut := root; return;
        case t_open_bracket =>
          ok := lexer.Next();
          if !ok { rootOut := null; return; }
          var key: Rope?;
          ok, key := ParseKey();
          if !ok { rootOut := null; return; }

          ok := lexer.Expect(t_close_bracket);
          if !ok { rootOut := null; return; }
          if !lexer.has_newline_before {
            var _ := lexer.ExpectedString([108, 105, 110, 101, 32, 98, 114, 101, 97, 107]);
          }

          var parentObject: Expr?;
          var err: SetError;
          ok, parentObject, err := rootObj.GetOrPutObject(key);
          if !ok {
            if err == Clobber {
              var _ := lexer.AddDefaultError([84, 97, 98, 108, 101, 32, 97, 108, 114, 101, 97, 100, 121, 32, 100, 101, 102, 105, 110, 101, 100]);
            }
            rootOut := null; return;
          }
          match parentObject.data
          case DObject(obj) => head := obj;
          case _ => ok := false; rootOut := null; return;
        case t_open_bracket_double =>
          ok := lexer.Next();
          if !ok { rootOut := null; return; }

          var key: Rope?;
          ok, key := ParseKey();
          if !ok { rootOut := null; return; }

          ok := lexer.Expect(t_close_bracket_double);
          if !ok { rootOut := null; return; }
          if !lexer.has_newline_before {
            var _ := lexer.ExpectedString([108, 105, 110, 101, 32, 98, 114, 101, 97, 107]);
          }

          var arrayExpr: Expr?;
          var err: SetError;
          ok, arrayExpr, err := rootObj.GetOrPutArray(key);
          if !ok {
            if err == Clobber {
              var _ := lexer.AddDefaultError([67, 97, 110, 110, 111, 116, 32, 111, 118, 101, 114, 119, 114, 105, 116, 101, 32, 116, 97, 98, 108, 101, 32, 97, 114, 114, 97, 121]);
            }
            rootOut := null; return;
          }
          var newHeadObj := new Object();
          var newHead := new Expr(DObject(newHeadObj), loc);
          match arrayExpr.data
          case DArray(arr) => arr.Push(newHead);
          case _ => ok := false; rootOut := null; return;
          head := newHeadObj;
        case _ =>
          ok := ParseAssignment(head);
          if !ok { rootOut := null; return; }
      }
    }

    method {:verify false} ParseAssignment(obj: Object) returns (ok: bool)
      modifies this, lexer, obj
      decreases *
    {
      lexer.allow_double_bracket := false;
      var rope: Rope?;
      ok, rope := ParseKey();
      if !ok { return; }
      var rope_end := lexer.start;

      var is_array := lexer.token == t_empty_array;
      if is_array {
        ok := lexer.Next();
        if !ok { return; }
      }

      ok := lexer.ExpectAssignment();
      if !ok { return; }
      if !is_array {
        var value: Expr?;
        ok, value := ParseValue();
        if !ok { return; }
        var err: SetError;
        ok, err := obj.SetRope(rope, value);
        if !ok {
          if err == Clobber {
            var loc := rope.head.loc;
            var src := lexer.source;
            var ignoredRopeEnd := rope_end; // preserves Rust local/update structure.
            var ignoredSrc := src;
            var ignoredAddError := lexer.AddError(loc.start, [67, 97, 110, 110, 111, 116, 32, 114, 101, 100, 101, 102, 105, 110, 101, 32, 107, 101, 121]);
          }
          return;
        }
      }
      lexer.allow_double_bracket := true;
      ok := true;
    }

    method {:verify false} ParseValue() returns (ok: bool, out: Expr?)
      modifies this, lexer
      decreases *
    {
      var safe := stack_check.IsSafeToRecurse();
      if !safe {
        ok := false; out := null; return;
      }
      ok, out := ParseValueInner();
    }

    method {:verify false} ParseValueInner() returns (ok: bool, out: Expr?)
      modifies this, lexer
      decreases *
    {
      var loc := lexer.Loc();
      lexer.allow_double_bracket := true;

      match lexer.token
      case t_false =>
        ok := lexer.Next();
        out := new Expr(DBoolean(false), loc);
      case t_true =>
        ok := lexer.Next();
        out := new Expr(DBoolean(true), loc);
      case t_string_literal =>
        var result := lexer.ToString(loc);
        ok := lexer.Next();
        out := result;
      case t_identifier =>
        var str := new Expr(DString(lexer.identifier), loc);
        ok := lexer.Next();
        out := str;
      case t_numeric_literal =>
        var value := lexer.number;
        ok := lexer.Next();
        out := new Expr(DNumber(value), loc);
      case t_minus =>
        ok := lexer.Next();
        if !ok { out := null; return; }
        var value := lexer.number;
        ok := lexer.Expect(t_numeric_literal);
        out := new Expr(DNumber(-value), loc);
      case t_plus =>
        ok := lexer.Next();
        if !ok { out := null; return; }
        var value := lexer.number;
        ok := lexer.Expect(t_numeric_literal);
        out := new Expr(DNumber(value), loc);
      case t_open_brace =>
        ok := lexer.Next();
        if !ok { out := null; return; }
        var is_single_line := !lexer.has_newline_before;
        var obj := new Object();
        var expr := new Expr(DObject(obj), loc);

        while lexer.token != t_close_brace
          decreases *
        {
          if |obj.properties| > 0 {
            if lexer.has_newline_before { is_single_line := false; }
            var keepGoing: bool;
            ok, keepGoing := ParseMaybeTrailingComma(t_close_brace);
            if !ok { out := null; return; }
            if !keepGoing { break; }
            if lexer.has_newline_before { is_single_line := false; }
          }
          ok := ParseAssignment(obj);
          if !ok { out := null; return; }
          lexer.allow_double_bracket := false;
        }

        if lexer.has_newline_before { is_single_line := false; }
        lexer.allow_double_bracket := true;
        ok := lexer.Expect(t_close_brace);
        out := expr;
      case t_empty_array =>
        ok := lexer.Next();
        lexer.allow_double_bracket := true;
        var arr := new Array();
        out := new Expr(DArray(arr), loc);
      case t_open_bracket =>
        ok := lexer.Next();
        if !ok { out := null; return; }
        var is_single_line := !lexer.has_newline_before;
        var arr := new Array();
        var array_ := new Expr(DArray(arr), loc);
        lexer.allow_double_bracket := false;

        while lexer.token != t_close_bracket
          decreases *
        {
          if |arr.items| > 0 {
            if lexer.has_newline_before { is_single_line := false; }

            var keepGoing: bool;
            ok, keepGoing := ParseMaybeTrailingComma(t_close_bracket);
            if !ok { out := null; return; }
            if !keepGoing { break; }

            if lexer.has_newline_before { is_single_line := false; }
          }

          var value: Expr?;
          ok, value := ParseValue();
          if !ok { out := null; return; }
          arr.Push(value);
        }

        if lexer.has_newline_before { is_single_line := false; }
        lexer.allow_double_bracket := true;
        ok := lexer.Expect(t_close_bracket);
        out := array_;
      case _ =>
        var _ := lexer.Unexpected();
        ok := false;
        out := null;
    }
  }

  method {:verify false} Sanity()
    decreases *
  {
    var loc := new Loc(0);
    var root := new Object();
    var keyExpr := new Expr(DString([97]), loc);
    var rope := new Rope(keyExpr, null);
    var val := new Expr(DNumber(1.0), loc);
    var ok: bool;
    var err: SetError;
    ok, err := root.SetRope(rope, val);
    assert ok;
    assert |root.properties| == 1;

    var src := new Source([97, 61, 49]);
    var stream := [LexItem(t_identifier, [97], 0.0, 0, false),
                   LexItem(t_equal, [], 0.0, 1, false),
                   LexItem(t_numeric_literal, [49], 1.0, 2, false)];
    var parsed: Expr?;
    ok, parsed := TOML.Parse(src, stream);
    assert ok;
  }
}

